(function () {
  // -------------------- Config (defaults) --------------------
  const script = document.currentScript;
  const CONFIG = {
    webhookUrl:
      (script && script.dataset.webhook) ||
      "https://n8n.alwaysencrypted.com/webhook/83cfae4a-71be-4123-81c4-99c9ab27a44b",
    logoUrl:
      (script && script.dataset.logo) ||
      "https://cdn.prod.website-files.com/6784053e7b7422e48efa5a84/6833a36f90c60fba010cee72_start_my_business_logo-removebg-preview.png",
    accent: (script && script.dataset.accent) || "#4493f2",
    position: (script && script.dataset.position) || "bottom-right",
    autoOpen: (script && script.dataset.autoOpen) !== "off",
    greeting:
      (script && script.dataset.greeting) ||
      "Hi! Welcome to Start My Business Inc. Ask me anything about LLC formation, business credit, or getting started.",
    retellTokenUrl:
      (script && script.dataset.retellToken) ||
      "https://n8n.alwaysencrypted.com/webhook/5ff531e4-ac0d-4b62-a093-7ae18b53f3f4",
    agentId: (script && script.dataset.retellAgent) || "",
    dripWebhook:
      (script && script.dataset.dripWebhook) ||
      "https://n8n.alwaysencrypted.com/webhook/shelf-corp-drip-enroll",
  };

  const ensureSessionId = () => {
    let id = localStorage.getItem("smb_session_id");
    if (!id) {
      id = (crypto.randomUUID && crypto.randomUUID()) || String(Date.now()) + "-" + Math.random().toString(36).slice(2);
      localStorage.setItem("smb_session_id", id);
    }
    return id;
  };

  // -------------------- Lead storage --------------------
  const getStoredLead = () => {
    try {
      const raw = localStorage.getItem("smb_lead");
      return raw ? JSON.parse(raw) : null;
    } catch { return null; }
  };
  const storeLead = (lead) => {
    localStorage.setItem("smb_lead", JSON.stringify(lead));
  };
  let leadInfo = getStoredLead();
  let messageCount = 0;
  let leadFormShown = false;
  const transcript = [];
  let transcriptSent = false;

  // -------------------- Inject CSS --------------------
  const pos = CONFIG.position.includes("left") ? "left" : "right";
  const css = `
    :root{
      --accent:${CONFIG.accent}; --accent-2: color-mix(in srgb, ${CONFIG.accent} 70%, white);
      --text:#0f172a; --muted:#6b7280;
      --bg:#ffffff; --bot-bg:#f4f7ff; --border:#e6e9f2;
      --radius:22px; --shadow:0 24px 60px rgba(7, 23, 60, .16);
    }
    #smbWidget *{ box-sizing:border-box }
    #smbWidget{ position:fixed; ${pos}:20px; bottom:20px; z-index:9999; }
    #smbOverlay{ position:fixed; inset:0; background:rgba(15,23,42,.28); z-index:9998; display:none; }
    #smbOverlay[aria-hidden="false"]{ display:block; }
    #smbLauncher{
      position:fixed; ${pos}:20px; bottom:20px; z-index:9999;
      width:64px; height:64px; border-radius:50%; border:0; cursor:pointer;
      background:#fff; box-shadow:0 14px 32px rgba(68,147,242,.30);
      display:grid; place-items:center; padding:0;
    }
    #smbLauncher img{ width:44px; height:44px; object-fit:contain; border-radius:50%; }
    #smbPanel{ display:none; }
    #smbPanel[aria-hidden="false"]{ display:block; }
    #smbPanel .smb-chat{
      width:min(420px, 94vw); height:min(720px, 90vh);
      background:var(--bg); border:1px solid var(--border);
      border-radius:28px; box-shadow:var(--shadow); overflow:hidden;
      display:grid; grid-template-rows:auto 1fr auto;
      font:16px/1.45 system-ui,-apple-system,Segoe UI,Roboto,Arial,sans-serif;
      color:var(--text);
    }
    #smbPanel .smb-hdr{ display:flex; align-items:center; justify-content:space-between; gap:12px; padding:16px 18px; border-bottom:1px solid var(--border); background:#fff }
    #smbPanel .hdr-left{ display:flex; align-items:center; gap:12px; }
    #smbPanel .smb-logo{ width:36px; height:36px; border-radius:12px; display:grid; place-items:center; background:#fff; border:1px solid var(--border); overflow:hidden; }
    #smbPanel .smb-logo img{ width:100%; height:100%; object-fit:contain; padding:4px }
    #smbPanel .smb-title{ font-weight:800; font-size:18px; color:var(--text) !important; text-shadow:none !important; letter-spacing:.2px; margin:0; line-height:1.2; }
    #smbPanel .smb-sub{ font-size:12px; color:var(--muted); text-shadow:none !important; display:flex; align-items:center; gap:8px }
    #smbPanel .smb-dot{ width:8px; height:8px; border-radius:50%; background:#22c55e; box-shadow:0 0 0 4px rgba(34,197,94,.15) }
    #smbPanel .smb-close{ border:0; background:#fff; color:var(--muted); font-size:22px; line-height:1; cursor:pointer }
    #smbPanel .smb-msgs{ padding:10px 14px 14px; overflow:auto; background:linear-gradient(180deg,#f7f9ff 0%, #ffffff 100%); }
    #smbPanel .voice-tip{
      position:sticky; top:0; z-index:2;
      display:flex; align-items:center; gap:12px;
      margin:0 0 8px 0; padding:10px 12px;
      background:#fff; border:1px solid var(--border); border-radius:16px;
      box-shadow:0 10px 18px rgba(9,30,66,.06);
    }
    #smbPanel .voice-tip.hidden{ display:none; }
    #smbPanel .voice-tip .blob-mini{
      width:46px; height:46px; flex:0 0 46px; border-radius:50%;
      background:radial-gradient(60% 60% at 40% 35%, #eaf3ff 0%, #bcd7ff 35%, #7db6ff 65%, #4493f2 100%);
      animation:blobWobble 6s ease-in-out infinite; box-shadow:0 12px 30px rgba(68,147,242,.25);
    }
    @keyframes blobWobble{ 0%,100%{transform:translateY(0)} 50%{transform:translateY(4px)} }
    #smbPanel .voice-tip .tip-text{ line-height:1.25 }
    #smbPanel .voice-tip .tip-title{ font-weight:800; }
    #smbPanel .voice-tip .tip-sub{ font-size:12px; color:var(--muted) }
    #smbPanel .tip-mic{
      margin-left:auto; width:46px; height:46px; border:none; border-radius:12px; cursor:pointer;
      background:linear-gradient(135deg,var(--accent-2),var(--accent)); color:#fff;
      display:grid; place-items:center; box-shadow:0 14px 28px rgba(68,147,242,.28);
    }
    #smbPanel .tip-mic svg{ width:24px; height:24px }
    #smbPanel .msg{ display:flex; margin:10px 6px }
    #smbPanel .msg.user{ justify-content:flex-end }
    #smbPanel .bubble{ max-width:78%; border-radius:18px; padding:14px 16px; box-shadow:0 8px 22px rgba(9,30,66,.08) }
    #smbPanel .msg.bot .bubble{ background:var(--bot-bg); color:var(--text); border:1px solid var(--border) }
    #smbPanel .msg.user .bubble{ color:#fff; background:linear-gradient(135deg, var(--accent-2), var(--accent)); border:0 }
    #smbPanel .bubble.streaming{ opacity:.9 }
    #smbPanel .typing{ display:flex; gap:6px; align-items:center; margin:10px 10px; }
    #smbPanel .dot{ width:8px; height:8px; border-radius:50%; background:#c3d9ff; animation:blink 1s infinite }
    #smbPanel .dot:nth-child(2){ animation-delay:.15s } #smbPanel .dot:nth-child(3){ animation-delay:.3s }
    @keyframes blink{ 0%,100%{opacity:.45} 50%{opacity:1} }
    #smbPanel .smb-input{ padding:12px; border-top:1px solid var(--border); background:#fff }
    #smbPanel .input-wrap{
      display:grid; grid-template-columns:1fr auto auto; gap:10px;
      border:1px solid var(--border); border-radius:9999px; padding:6px 8px; background:#fff
    }
    #smbPanel .input-wrap input{ border:0; outline:0; padding:10px 12px; font:inherit; color:var(--text) }
    #smbPanel .btn{ width:42px; height:42px; display:grid; place-items:center; border:0; background:var(--accent); color:#fff; border-radius:14px; cursor:pointer; box-shadow:0 12px 28px rgba(68,147,242,.35) }
    #smbPanel .btn:hover{ filter:brightness(1.06) }
    #smbPanel .icon-btn{
      width:42px; height:42px; display:grid; place-items:center;
      border:1px solid var(--border); background:#fff; color:var(--accent);
      border-radius:14px; cursor:pointer;
    }
    #smbPanel .icon-btn:hover{ box-shadow:0 6px 16px rgba(68,147,242,.15) }
    #smbPanel .icon-btn svg{ width:22px; height:22px }
    #smbPanel .smb-msgs::-webkit-scrollbar{ width:10px }
    #smbPanel .smb-msgs::-webkit-scrollbar-thumb{ background:#e3e8f5; border-radius:10px }
    #smbPanel .msg.bot .bubble { position: relative; }
    #smbPanel .bubble-actions{ display:flex; gap:14px; margin:8px 6px 0 6px; opacity:0; transition:opacity .18s ease; }
    #smbPanel .msg.bot:hover .bubble-actions{ opacity:1; }
    @media (hover:none){ #smbPanel .bubble-actions{ opacity:1; } }
    #smbPanel .action-btn{ width:32px; height:32px; display:grid; place-items:center; background:transparent; border:none; color:var(--muted); cursor:pointer; border-radius:8px; }
    #smbPanel .action-btn:hover{ color:var(--text); }
    #smbPanel .action-btn.like.liked{ color:var(--accent); }
    #smbPanel .action-btn svg{ width:22px; height:22px }
    #smbPanel .action-btn svg *{ stroke:currentColor; fill:none; stroke-width:2; stroke-linecap:round; stroke-linejoin:round }
    #smbPanel .toast{
      position:fixed; ${pos}:26px; bottom:96px;
      background:#111827; color:#fff; padding:8px 12px; border-radius:10px; font-size:12px;
      opacity:0; transform:translateY(8px); transition:opacity .2s, transform .2s;
    }
    #smbPanel .toast.show{ opacity:1; transform:translateY(0); }
    #smbPanel .voice-dock{
      position:absolute; left:12px; right:12px; bottom:74px;
      background:#fff; border:1px solid var(--border); border-radius:20px;
      box-shadow:0 16px 40px rgba(68,147,242,.15);
      padding:14px; display:none; z-index:3;
    }
    #smbPanel .voice-dock[aria-hidden="false"]{ display:block; }
    #smbPanel .voice-row{ display:grid; grid-template-columns:1fr auto; align-items:center; gap:14px; }
    #smbPanel .voice-left{ display:grid; grid-template-columns:auto 1fr; gap:12px; align-items:center; }
    #smbPanel .dock-controls{ display:flex; align-items:center; gap:10px; }
    #smbPanel .dock-mic{
      width:54px; height:54px; border-radius:50%; border:none; cursor:pointer;
      background:linear-gradient(135deg,var(--accent-2),var(--accent)); color:#fff;
      display:grid; place-items:center; box-shadow:0 18px 40px rgba(68,147,242,.35);
    }
    #smbPanel .dock-mic[aria-pressed="true"]{ filter:brightness(.94) }
    #smbPanel .dock-mic svg{ width:26px; height:26px }
    #smbPanel .dock-x{
      width:40px; height:40px; border-radius:10px; border:1px solid var(--border);
      background:#fff; color:var(--text); display:grid; place-items:center; cursor:pointer;
    }
    #smbPanel .dock-status{ font-size:12px; color:var(--muted); margin-top:8px; padding-left:76px; }
    #smbPanel .lead-overlay{
      position:absolute; inset:0; z-index:10;
      background:rgba(255,255,255,.96); backdrop-filter:blur(6px);
      display:flex; align-items:center; justify-content:center;
      padding:20px; border-radius:28px;
    }
    #smbPanel .lead-overlay.hidden{ display:none; }
    #smbPanel .lead-form{
      width:100%; max-width:340px; text-align:center;
    }
    #smbPanel .lead-form h3{
      font-size:20px; font-weight:800; margin:0 0 6px 0; color:var(--text);
    }
    #smbPanel .lead-form p{
      font-size:14px; color:var(--muted); margin:0 0 20px 0; line-height:1.4;
    }
    #smbPanel .lead-form input{
      display:block; width:100%; padding:14px 16px; margin:0 0 12px 0;
      border:1px solid var(--border); border-radius:14px; font:inherit;
      color:var(--text); background:#fff; outline:none;
    }
    #smbPanel .lead-form input:focus{
      border-color:var(--accent); box-shadow:0 0 0 3px rgba(68,147,242,.12);
    }
    #smbPanel .lead-form button{
      width:100%; padding:14px; border:none; border-radius:14px; cursor:pointer;
      font:inherit; font-weight:700; color:#fff;
      background:linear-gradient(135deg, var(--accent-2), var(--accent));
      box-shadow:0 14px 28px rgba(68,147,242,.28);
    }
    #smbPanel .lead-form button:hover{ filter:brightness(1.05); }
    #smbPanel .lead-form .lead-error{
      color:#ef4444; font-size:13px; margin:0 0 8px 0; display:none;
    }
  `;
  const style = document.createElement("style");
  style.id = "smb-widget-style";
  style.textContent = css;
  document.head.appendChild(style);

  // -------------------- DOM skeleton --------------------
  const overlay = document.createElement("div");
  overlay.id = "smbOverlay";
  overlay.setAttribute("aria-hidden", "true");
  document.body.appendChild(overlay);

  const launcher = document.createElement("button");
  launcher.id = "smbLauncher";
  launcher.setAttribute("aria-label", "Open chat");
  const launcherImg = document.createElement("img");
  launcherImg.alt = "StartMyBusiness";
  launcherImg.src = CONFIG.logoUrl;
  launcher.appendChild(launcherImg);
  document.body.appendChild(launcher);

  const root = document.createElement("div");
  root.id = "smbWidget";
  const panel = document.createElement("div");
  panel.id = "smbPanel";
  panel.setAttribute("aria-hidden", "true");
  root.appendChild(panel);

  const chat = document.createElement("div");
  chat.className = "smb-chat";
  chat.setAttribute("role", "dialog");
  chat.setAttribute("aria-label", "StartMyBusiness Chat");

  // Header
  const hdr = document.createElement("div");
  hdr.className = "smb-hdr";
  hdr.innerHTML = '<div class="hdr-left"><div class="smb-logo" aria-hidden="true"><img src="' + CONFIG.logoUrl + '" alt="StartMyBusiness logo"></div><div><div class="smb-title">Start My Business Inc</div><div class="smb-sub"><span class="smb-dot" aria-hidden="true"></span> Online • We reply instantly</div></div></div><button id="smbClose" class="smb-close" aria-label="Close">\u00d7</button>';

  // Voice dock
  const voiceDockEl = document.createElement("div");
  voiceDockEl.id = "smbVoiceDock";
  voiceDockEl.className = "voice-dock";
  voiceDockEl.setAttribute("aria-hidden", "true");
  voiceDockEl.innerHTML = '<div class="voice-row"><div class="voice-left"><div class="blob-mini" aria-hidden="true"></div><div><div class="voice-title">Voice agent</div><div class="voice-sub">Tap to talk. Tap again to stop.</div></div></div><div class="dock-controls"><button id="smbDockMic" class="dock-mic" aria-pressed="false" aria-label="Start voice call"><svg viewBox="0 0 24 24" fill="none"><path d="M12 14a3 3 0 0 0 3-3V7a3 3 0 1 0-6 0v4a3 3 0 0 0 3 3Z" fill="#fff"/><path d="M5 11a7 7 0 0 0 14 0" stroke="#fff" stroke-width="2"/><path d="M12 18v4" stroke="#fff" stroke-width="2"/></svg></button><button id="smbDockClose" class="dock-x" title="Close"><svg viewBox="0 0 24 24" fill="none"><path d="M6 6l12 12M18 6l-12 12" stroke="currentColor" stroke-width="2"/></svg></button></div></div><div id="smbDockStatus" class="dock-status">Idle</div>';

  // Messages area
  const msgsEl = document.createElement("div");
  msgsEl.className = "smb-msgs";
  msgsEl.id = "smbMsgs";
  msgsEl.setAttribute("aria-live", "polite");

  // Voice tip banner
  const voiceTipEl = document.createElement("div");
  voiceTipEl.id = "smbVoiceTip";
  voiceTipEl.className = "voice-tip";
  voiceTipEl.setAttribute("role", "status");
  voiceTipEl.setAttribute("aria-label", "Tap to talk");
  voiceTipEl.innerHTML = '<div class="blob-mini" aria-hidden="true"></div><div class="tip-text"><div class="tip-title">Tap to talk</div><div class="tip-sub">Speak to our voice agent anytime.</div></div><button id="smbTipMic" class="tip-mic" aria-label="Start voice call"><svg viewBox="0 0 24 24" fill="none" aria-hidden="true"><path d="M12 14a3 3 0 0 0 3-3V7a3 3 0 1 0-6 0v4a3 3 0 0 0 3 3Z" stroke="#fff" stroke-width="2"/><path d="M5 11a7 7 0 0 0 14 0" stroke="#fff" stroke-width="2"/><path d="M12 18v4" stroke="#fff" stroke-width="2"/></svg></button>';
  msgsEl.appendChild(voiceTipEl);

  // Lead capture overlay (v4.3)
  const leadOverlay = document.createElement("div");
  leadOverlay.id = "smbLeadOverlay";
  leadOverlay.className = "lead-overlay hidden";
  leadOverlay.innerHTML = '<div class="lead-form"><h3>Before we continue...</h3><p>Share your info so we can better assist you and follow up with helpful resources.</p><p class="lead-error" id="smbLeadError">Please fill in both fields.</p><input type="text" id="smbLeadName" placeholder="First name" autocomplete="given-name" /><input type="email" id="smbLeadEmail" placeholder="Email address" autocomplete="email" /><button id="smbLeadSubmit">Continue chatting</button></div>';

  // Input area
  const inputArea = document.createElement("div");
  inputArea.className = "smb-input";
  inputArea.innerHTML = '<div class="input-wrap"><input id="smbInput" type="text" placeholder="Send message..." autocomplete="off" /><button id="smbBtnMicInline" class="icon-btn" title="Talk"><svg viewBox="0 0 24 24" fill="none"><path d="M12 14a3 3 0 0 0 3-3V7a3 3 0 1 0-6 0v4a3 3 0 0 0 3 3Z" stroke="currentColor"/><path d="M5 11a7 7 0 0 0 14 0" stroke="currentColor"/><path d="M12 18v4" stroke="currentColor"/></svg></button><button class="btn" id="smbBtnSend" title="Send"><svg width="22" height="22" viewBox="0 0 24 24"><path d="M3 21L21 12L3 3v7l11 2-11 2z" fill="currentColor" stroke="none"/></svg></button></div>';

  chat.appendChild(hdr);
  chat.appendChild(voiceDockEl);
  chat.appendChild(msgsEl);
  chat.appendChild(leadOverlay);
  chat.appendChild(inputArea);
  panel.appendChild(chat);
  document.body.appendChild(root);

  // -------------------- Open / Close helpers --------------------
  const closeBtn = panel.querySelector("#smbClose");
  const openPanel = () => {
    panel.setAttribute("aria-hidden", "false");
    overlay.setAttribute("aria-hidden", "false");
    document.body.style.overflow = "hidden";
  };
  const sendTranscript = () => {
    if (transcriptSent || transcript.length < 2) return;
    transcriptSent = true;
    const payload = {
      sessionId: SESSION_ID,
      transcript: transcript,
      name: leadInfo ? leadInfo.name : "Anonymous",
      email: leadInfo ? leadInfo.email : "Not provided",
      page: window.location.href,
      closedAt: new Date().toISOString()
    };
    fetch(CONFIG.webhookUrl.replace("83cfae4a-71be-4123-81c4-99c9ab27a44b", "smb-chat-transcript"), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
      keepalive: true
    }).catch(() => {});
  };

  const closePanel = () => {
    panel.setAttribute("aria-hidden", "true");
    overlay.setAttribute("aria-hidden", "true");
    document.body.style.overflow = "";
    sendTranscript();
  };
  launcher.addEventListener("click", openPanel);
  closeBtn.addEventListener("click", closePanel);
  overlay.addEventListener("click", closePanel);
  window.addEventListener("keydown", (e) => { if (e.key === "Escape") closePanel(); });

  window.SMBWidget = {
    open: (opts = {}) => { openPanel(); if (opts.greeting) maybeGreet(opts.greeting); },
    close: closePanel,
    toggle: () => panel.getAttribute("aria-hidden") === "true" ? openPanel() : closePanel(),
    isOpen: () => panel.getAttribute("aria-hidden") === "false",
  };

  // -------------------- Chat wiring --------------------
  const inputEl = panel.querySelector("#smbInput");
  const btnSend = panel.querySelector("#smbBtnSend");
  const SESSION_ID = ensureSessionId();
  let greetedThisSession = false;
  let pendingMessage = null;

  const addMsg = (role, text, opts = {}) => {
    const wrap = document.createElement("div");
    wrap.className = "msg " + (role === "user" ? "user" : "bot");
    const bubble = document.createElement("div");
    bubble.className = "bubble" + (opts.streaming ? " streaming" : "");
    bubble.textContent = text;
    wrap.appendChild(bubble);
    if (role === "bot") {
      const actions = document.createElement("div");
      actions.className = "bubble-actions";
      actions.setAttribute("role", "group");
      actions.setAttribute("aria-label", "Message actions");
      actions.innerHTML = '<button class="action-btn copy" title="Copy"><svg viewBox="0 0 24 24"><rect x="9" y="9" width="11" height="11" rx="2"></rect><rect x="4" y="4" width="11" height="11" rx="2"></rect></svg></button><button class="action-btn like" title="Like"><svg viewBox="0 0 24 24"><path d="M2 10h4v10H2z"></path><path d="M8 20h8.5a3 3 0 0 0 3-2.4l1.1-5A2 2 0 0 0 18.7 10H14V6a3 3 0 0 0-3-3l-3 7v10z"></path></svg></button>';
      wrap.appendChild(actions);
    }
    msgsEl.appendChild(wrap);
    msgsEl.scrollTop = msgsEl.scrollHeight;
    if (!opts.streaming) {
      transcript.push({ role, text, time: new Date().toISOString() });
    }
    return bubble;
  };

  const showTyping = (show) => {
    let row = panel.querySelector("#smbTyping");
    if (show) {
      if (!row) {
        row = document.createElement("div");
        row.id = "smbTyping";
        row.className = "typing";
        row.innerHTML = '<span class="dot"></span><span class="dot"></span><span class="dot"></span>';
        msgsEl.appendChild(row);
      }
    } else if (row) { row.remove(); }
    msgsEl.scrollTop = msgsEl.scrollHeight;
  };

  const sendToN8n = async (message) => {
    const payload = { message, sessionId: SESSION_ID };
    if (leadInfo) {
      payload.name = leadInfo.name;
      payload.firstName = leadInfo.name;
      payload.email = leadInfo.email;
    }
    const res = await fetch(CONFIG.webhookUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    const ct = res.headers.get("content-type") || "";
    if (ct.includes("application/json")) {
      const data = await res.json();
      let reply = data.output ?? data.reply ?? data.response ?? data.message ?? data.text ?? (data.data && (data.data.output || data.data.reply || data.data.response || data.data.text));
      if (!reply && Array.isArray(data.messages) && data.messages.length) {
        const last = data.messages[data.messages.length - 1];
        reply = last.text || last.message || last.response || last.output;
      }
      return reply || JSON.stringify(data);
    }
    return await res.text();
  };

  const toast = (msg) => {
    let t = document.getElementById("smbToast");
    if (!t) { t = document.createElement("div"); t.id = "smbToast"; t.className = "toast"; document.body.appendChild(t); }
    t.textContent = msg;
    t.classList.add("show");
    clearTimeout(toast._timer);
    toast._timer = setTimeout(() => t.classList.remove("show"), 1400);
  };

  // -------------------- Lead capture (v4.3) --------------------
  function showLeadForm() {
    if (leadFormShown || leadInfo) return;
    leadFormShown = true;
    leadOverlay.classList.remove("hidden");
    const nameInput = panel.querySelector("#smbLeadName");
    setTimeout(() => nameInput && nameInput.focus(), 200);
  }

  function hideLeadForm() {
    leadOverlay.classList.add("hidden");
  }

  const enrollInDrip = (name, email) => {
    fetch(CONFIG.dripWebhook, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        name: name,
        firstName: name,
        email: email,
        sessionId: SESSION_ID,
        source: "chatbot",
        page: window.location.href,
        timestamp: new Date().toISOString()
      }),
    }).catch(() => {});
  };

  const leadSubmitBtn = panel.querySelector("#smbLeadSubmit");
  const leadError = panel.querySelector("#smbLeadError");

  leadSubmitBtn.addEventListener("click", () => {
    const nameVal = panel.querySelector("#smbLeadName").value.trim();
    const emailVal = panel.querySelector("#smbLeadEmail").value.trim();
    if (!nameVal || !emailVal || !emailVal.includes("@")) {
      leadError.style.display = "block";
      leadError.textContent = !nameVal ? "Please enter your first name." : "Please enter a valid email.";
      return;
    }
    leadError.style.display = "none";
    leadInfo = { name: nameVal, email: emailVal };
    storeLead(leadInfo);
    hideLeadForm();
    addMsg("bot", "Thanks, " + nameVal + "! How can I help you today?");
    enrollInDrip(nameVal, emailVal);
    if (pendingMessage) {
      const msg = pendingMessage;
      pendingMessage = null;
      doSend(msg);
    }
  });

  // Allow Enter to submit lead form
  panel.querySelector("#smbLeadEmail").addEventListener("keydown", (e) => {
    if (e.key === "Enter") { e.preventDefault(); leadSubmitBtn.click(); }
  });
  panel.querySelector("#smbLeadName").addEventListener("keydown", (e) => {
    if (e.key === "Enter") { e.preventDefault(); panel.querySelector("#smbLeadEmail").focus(); }
  });

  // -------------------- Send logic --------------------
  async function doSend(text) {
    showTyping(true);
    try {
      const reply = await sendToN8n(text);
      showTyping(false);
      addMsg("bot", String(reply));
    } catch (err) {
      showTyping(false);
      addMsg("bot", "Sorry, I couldn't reach the assistant. (" + err.message + ")");
    }
  }

  async function handleSend() {
    const text = inputEl.value.trim();
    if (!text) return;
    addMsg("user", text);
    inputEl.value = "";
    messageCount++;

    if (!leadInfo && messageCount >= 1) {
      pendingMessage = text;
      showLeadForm();
      return;
    }

    await doSend(text);
  }

  btnSend.addEventListener("click", handleSend);
  inputEl.addEventListener("keydown", (e) => { if (e.key === "Enter") { e.preventDefault(); handleSend(); } });

  msgsEl.addEventListener("click", async (e) => {
    const btn = e.target.closest(".action-btn");
    if (!btn) return;
    const row = btn.closest(".msg");
    const text = row?.querySelector(".bubble")?.textContent || "";
    if (btn.classList.contains("copy")) {
      try { await navigator.clipboard.writeText(text); toast("Copied"); } catch { toast("Copy failed"); }
    }
    if (btn.classList.contains("like")) {
      btn.classList.toggle("liked");
      toast(btn.classList.contains("liked") ? "Thanks!" : "Like removed");
    }
  });

  function maybeGreet(customText) {
    if (greetedThisSession) return;
    addMsg("bot", customText || CONFIG.greeting);
    greetedThisSession = true;
  }

  // -------------------- Voice (Retell) --------------------
  const voiceDock = panel.querySelector("#smbVoiceDock");
  const btnMicInline = panel.querySelector("#smbBtnMicInline");
  const dockMic = panel.querySelector("#smbDockMic");
  const dockClose = panel.querySelector("#smbDockClose");
  const dockStatus = panel.querySelector("#smbDockStatus");
  const tipMic = panel.querySelector("#smbTipMic");
  const voiceTip = panel.querySelector("#smbVoiceTip");

  let inCall = false;
  let retell = null;
  let isLoadingSDK = false;
  let agentStreamBubble = null;

  function openDock() { voiceDock.setAttribute("aria-hidden", "false"); }
  function closeDock() { voiceDock.setAttribute("aria-hidden", "true"); if (inCall) stopCall(); }
  dockClose.addEventListener("click", closeDock);

  async function ensureRetell() {
    if (retell) return retell;
    if (isLoadingSDK) {
      return new Promise((resolve, reject) => {
        const checkInterval = setInterval(() => {
          if (retell) { clearInterval(checkInterval); resolve(retell); }
          else if (!isLoadingSDK) { clearInterval(checkInterval); reject(new Error("SDK load failed")); }
        }, 100);
        setTimeout(() => { clearInterval(checkInterval); reject(new Error("SDK load timeout")); }, 15000);
      });
    }
    isLoadingSDK = true;
    try {
      const mod = await import("https://esm.sh/retell-client-js-sdk@2?bundle&target=es2020");
      const { RetellWebClient } = mod || {};
      if (!RetellWebClient) throw new Error("Retell Web SDK failed to load.");
      retell = new RetellWebClient();
      return retell;
    } finally { isLoadingSDK = false; }
  }

  const acquireAccessToken = async () => {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 15000);
    try {
      const r = await fetch(CONFIG.retellTokenUrl, {
        method: "POST",
        headers: { "Content-Type": "application/json", "cache-control": "no-store" },
        body: JSON.stringify({ sessionId: SESSION_ID, agentId: CONFIG.agentId || undefined }),
        signal: controller.signal
      });
      clearTimeout(timeoutId);
      const j = await r.json().catch(() => ({}));
      if (!r.ok || !j.access_token) { console.error("Token response:", j); throw new Error(j.error || j.message || "No access_token"); }
      return j.access_token;
    } catch (err) { clearTimeout(timeoutId); if (err.name === 'AbortError') throw new Error("Token request timed out"); throw err; }
  };

  const streamAgentText = (text) => {
    if (!agentStreamBubble) { agentStreamBubble = addMsg("bot", text || "", { streaming: true }); }
    else if (agentStreamBubble.textContent !== text) { agentStreamBubble.textContent = text || ""; msgsEl.scrollTop = msgsEl.scrollHeight; }
  };
  const endAgentStream = () => { if (agentStreamBubble) agentStreamBubble.classList.remove("streaming"); agentStreamBubble = null; };

  async function requestMicrophoneAccess() {
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
      throw new Error("Your browser doesn't support microphone access.");
    }
    try {
      await navigator.mediaDevices.getUserMedia({ audio: true });
      return true;
    } catch (err) {
      if (err.name === 'NotAllowedError') throw new Error("Microphone permission denied. Please allow mic access in browser settings.");
      if (err.name === 'NotFoundError') throw new Error("No microphone found. Please connect a microphone.");
      if (err.name === 'NotReadableError') throw new Error("Microphone in use by another app.");
      if (err.name === 'SecurityError') throw new Error("Microphone requires HTTPS.");
      throw new Error("Microphone error: " + (err.message || err.name));
    }
  }

  async function startCall() {
    if (inCall) { await stopCall(); return; }
    try {
      if (retell) { try { retell.stopCall(); } catch (e) {} retell = null; }
      await ensureRetell();
      openDock();
      voiceTip.classList.add("hidden");
      dockStatus.textContent = "Requesting microphone...";
      try { await requestMicrophoneAccess(); } catch (micErr) { dockStatus.textContent = "Mic access failed"; addMsg("bot", micErr.message); voiceTip.classList.remove("hidden"); return; }
      dockStatus.textContent = "Connecting...";
      dockMic.setAttribute("aria-pressed", "true");
      const token = await acquireAccessToken();
      await retell.startCall({ accessToken: token });
      inCall = true;
      dockStatus.textContent = "Listening... tap to stop";
      retell.on("call_started", () => { dockStatus.textContent = "Connected"; });
      retell.on("call_ended", () => { dockStatus.textContent = "Ended"; inCall = false; dockMic.setAttribute("aria-pressed", "false"); endAgentStream(); voiceTip.classList.remove("hidden"); });
      retell.on("update", (u) => { const t = u && Array.isArray(u.transcript) ? u.transcript.at(-1) : null; if (t && t.content && t.role === "agent") streamAgentText(t.content); });
      retell.on("error", (err) => { console.error("Retell error:", err); addMsg("bot", "Voice error: " + (err?.message || String(err))); dockStatus.textContent = "Error"; try { retell.stopCall(); } catch (_e) {} inCall = false; dockMic.setAttribute("aria-pressed", "false"); endAgentStream(); voiceTip.classList.remove("hidden"); });
    } catch (err) {
      console.error("Voice start error:", err);
      let msg = "Failed to start voice.";
      if (err.message.includes("access_token")) msg = "Could not connect to voice service.";
      else if (err.message.includes("SDK")) msg = "Voice feature failed to load. Please refresh.";
      else if (err.message.includes("timeout")) msg = "Connection timed out.";
      else if (err.message) msg = err.message;
      addMsg("bot", msg);
      dockStatus.textContent = "Failed";
      dockMic.setAttribute("aria-pressed", "false");
      inCall = false;
      voiceTip.classList.remove("hidden");
    }
  }

  async function stopCall() {
    try { if (retell) await retell.stopCall(); } catch (_) {}
    inCall = false;
    dockMic.setAttribute("aria-pressed", "false");
    dockStatus.textContent = "Ended";
    endAgentStream();
    voiceTip.classList.remove("hidden");
  }

  const startFromTip = async (e) => { e?.stopPropagation?.(); if (!inCall) await startCall(); else await stopCall(); };
  tipMic.addEventListener("click", startFromTip);
  voiceTip.addEventListener("click", async () => { if (!inCall) await startCall(); });
  btnMicInline.addEventListener("click", startFromTip);
  dockMic.addEventListener("click", startFromTip);

  // -------------------- Send transcript on page leave --------------------
  window.addEventListener("beforeunload", sendTranscript);

  // -------------------- Auto-open once per session --------------------
  if (CONFIG.autoOpen) {
    const key = "smb_auto_opened";
    if (!sessionStorage.getItem(key)) { openPanel(); maybeGreet(); sessionStorage.setItem(key, "1"); }
  }
})();
